  ('social-worker-moex-01899', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '針對研究問題：「在新福利政策影響下，福利接受者如何經驗政策更新對生活的改變。」研究者採取質 性深度訪談，從福利接受者的觀點，了解新福利政策對其生活帶來的影響，這種研究設計是那一種典範？', '["實證主義", "批判理論", "女性主義", "詮釋論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
